const errorData = $input.first().json;
const workflowName = errorData.workflow?.name || 'Unknown';
const errorMessage = errorData.execution?.error?.message || 'No error message';
const errorNode = errorData.execution?.error?.node?.name || 'Unknown';
const executionId = errorData.execution?.id || 'N/A';
const workflowEmojis = {'0': '🔑', '1': '📊', '2': '🤖', '3': '💼', '4': '⚡', '5': '⏰', '6': '🚨'};
const emoji = workflowEmojis[workflowName.charAt(0)] || '⚠️';
let errorType = 'UNKNOWN', severity = 'MEDIUM';
const el = errorMessage.toLowerCase();
if (el.includes('credit') || el.includes('quota') || el.includes('429')) { errorType = 'CREDIT_BILLING'; severity = 'CRITICAL'; }
else if (el.includes('timeout')) { errorType = 'TIMEOUT'; severity = 'LOW'; }
else if (el.includes('auth') || el.includes('401') || el.includes('403')) { errorType = 'AUTH'; severity = 'HIGH'; }
const severityEmoji = {'CRITICAL': '🔴🔴🔴', 'HIGH': '🔴', 'MEDIUM': '🟡', 'LOW': '🟢'};
return [{json: {workflowName, errorMessage: errorMessage.substring(0,300), errorNode, executionId, emoji, errorType, severity, severityEmoji: severityEmoji[severity], errorTimestamp: new Date().toISOString()}}];
